public class TestBadServerResponses { private static final Logger LOG = LoggerFactory . getLogger ( MethodHandles . lookup ( ) . lookupClass ( ) ) ; private OkHttp http ; private ServerSocket server ; private Configuration conf ; private int port = 47506 ; private static final String responseHeader = "HTTP/1.1 200 OK\r\n" ; private static final String simpleContent = "Content-Type: text/html\r\n\r\nThis is a text." ; public void setUp ( ) throws Exception { conf = new Configuration ( ) ; conf . addResource ( "nutch-default.xml" ) ; conf . addResource ( "nutch-site-test.xml" ) ; conf . setBoolean ( "store.http.headers" , true ) ; http = new OkHttp ( ) ; http . setConf ( conf ) ; } @ After public void tearDown ( ) throws Exception { server . close ( ) ; } private void runServer ( int port , String response ) throws Exception { server = new ServerSocket ( ) ; server . bind ( new InetSocketAddress ( "127.0.0.1" , port ) ) ; Pattern requestPattern = Pattern . compile ( "(?i)^GET\\s+(\\S+)" ) ; while ( true ) { LOG . info ( "Listening on port {}" , port ) ; Socket socket = server . accept ( ) ; LOG . info ( "Connection received" ) ; try ( BufferedReader in = new BufferedReader ( new InputStreamReader ( socket . getInputStream ( ) , StandardCharsets . UTF_8 ) ) ; PrintWriter out = new PrintWriter ( new OutputStreamWriter ( socket . getOutputStream ( ) , StandardCharsets . UTF_8 ) , true ) ) { String line ; while ( ( line = in . readLine ( ) ) != null ) { LOG . info ( "Request: {}" , line ) ; if ( line . trim ( ) . isEmpty ( ) ) { break ; } Matcher m = requestPattern . matcher ( line ) ; if ( m . find ( ) ) { LOG . info ( "Requested {}" , m . group ( 1 ) ) ; if ( ! m . group ( 1 ) . startsWith ( "/" ) ) { response = "HTTP/1.1 400 Bad request\r\n\r\n" ; } } } LOG . info ( "Response: {}" , response . substring ( 0 , Math . min ( 1024 , response . length ( ) ) ) ) ; out . print ( response ) ; } catch ( Exception e ) { LOG . warn ( "Exception in test server:" , e ) ; } } } private void launchServer ( String response ) throws InterruptedException { Thread serverThread = new Thread ( ( ) -> { try { runServer ( port , response ) ; } catch ( Exception e ) { LOG . warn ( "Test server died:" , e ) ; } } ) ; serverThread . start ( ) ; Thread . sleep ( 50 ) ; } private Response fetchPage ( String page , int expectedCode ) throws Exception { URL url = new URL ( "http" , "127.0.0.1" , port , page ) ; LOG . info ( "Fetching {}" , url ) ; CrawlDatum crawlDatum = new CrawlDatum ( ) ; Response response = http . getResponse ( url , crawlDatum , true ) ; assertEquals ( "HTTP Status Code for " + url , expectedCode , response . getCode ( ) ) ; return response ; } @ Test public void testBadHttpServer ( ) throws Exception { setUp ( ) ; launchServer ( responseHeader + simpleContent ) ; fetchPage ( "/" , 200 ) ; } @ Test public void testRequestNotStartingWithSlash ( ) throws Exception { setUp ( ) ; launchServer ( responseHeader + simpleContent ) ; fetchPage ( "?171" , 200 ) ; } @ Test public void testContentLengthNotANumber ( ) throws Exception { setUp ( ) ; launchServer ( responseHeader + "Content-Length: thousand\r\n" + simpleContent ) ; fetchPage ( "/" , 200 ) ; } @ Ignore ( "Fails with okhttp 3.10.0" ) @ Test public void testHeaderWithColon ( ) throws Exception { setUp ( ) ; launchServer ( "HTTP/1.1 200: OK\r\n" + simpleContent ) ; fetchPage ( "/" , 200 ) ; } @ Test public void testHeaderSpellChecking ( ) throws Exception { setUp ( ) ; launchServer ( responseHeader + "Client-Transfer-Encoding: chunked\r\n" + simpleContent ) ; fetchPage ( "/" , 200 ) ; } @ Ignore ( "Fails with okhttp 3.10.0" ) @ Test public void testIgnoreErrorInRedirectPayload ( ) throws Exception { setUp ( ) ; launchServer ( "HTTP/1.1 302 Found\r\nLocation: http://example.com/\r\n" + "Transfer-Encoding: chunked\r\n\r\nNot a valid chunk." ) ; Response fetched = fetchPage ( "/" , 302 ) ; assertNotNull ( "No redirect Location." , fetched . getHeader ( "Location" ) ) ; assertEquals ( "Wrong redirect Location." , "http://example.com/" , fetched . getHeader ( "Location" ) ) ; } @ Ignore ( "Fails with okhttp 3.10.0" ) @ Test public void testNoStatusLine ( ) throws Exception { setUp ( ) ; String text = "This is a text containing non-ASCII characters: \u00e4\u00f6\u00fc\u00df" ; launchServer ( text ) ; Response fetched = fetchPage ( "/" , 200 ) ; assertEquals ( "Wrong text returned for response with no status line." , text , new String ( fetched . getContent ( ) , StandardCharsets . UTF_8 ) ) ; server . close ( ) ; text = "<!DOCTYPE html>\n<html>\n<head>\n" + "<title>Testing no HTTP header èéâ</title>\n" + "<meta charset=\"utf-8\">\n" + "</head>\n<body>This is a text containing non-ASCII characters:" + "\u00e4\u00f6\u00fc\u00df</body>\n</html" ; launchServer ( text ) ; fetched = fetchPage ( "/" , 200 ) ; assertEquals ( "Wrong text returned for response with no status line." , text , new String ( fetched . getContent ( ) , StandardCharsets . UTF_8 ) ) ; } @ Ignore ( "Fails with okhttp 3.10.0" ) @ Test public void testMultiLineHeader ( ) throws Exception { setUp ( ) ; launchServer ( responseHeader + "Set-Cookie: UserID=JohnDoe;\r\n  Max-Age=3600;\r\n  Version=1\r\n" + simpleContent ) ; Response fetched = fetchPage ( "/" , 200 ) ; LOG . info ( "Headers: {}" , fetched . getHeaders ( ) ) ; assertNotNull ( "Failed to set multi-line \"Set-Cookie\" header." , fetched . getHeader ( "Set-Cookie" ) ) ; assertTrue ( "Failed to set multi-line \"Set-Cookie\" header." , fetched . getHeader ( "Set-Cookie" ) . contains ( "Version=1" ) ) ; } @ Test ( expected = Exception . class ) public void testOverlongHeader ( ) throws Exception { setUp ( ) ; StringBuilder response = new StringBuilder ( ) ; response . append ( responseHeader ) ; for ( int i = 0 ; i < 80 ; i ++ ) { response . append ( "X-Custom-Header-" ) ; for ( int j = 0 ; j < 10000 ; j ++ ) { response . append ( 'x' ) ; } response . append ( ": hello\r\n" ) ; } response . append ( "\r\n" + simpleContent ) ; launchServer ( response . toString ( ) ) ; fetchPage ( "/" , 200 ) ; } @ Test public void testChunkedContent ( ) throws Exception { setUp ( ) ; StringBuilder response = new StringBuilder ( ) ; response . append ( responseHeader ) ; response . append ( "Content-Type: text/html\r\n" ) ; response . append ( "Transfer-Encoding: chunked\r\n" ) ; for ( int i = 0 ; i < 80 ; i ++ ) { response . append ( String . format ( "\r\n400\r\n%02x\r\n" , i ) ) ; for ( int j = 0 ; j < 1012 ; j ++ ) { response . append ( 'x' ) ; } response . append ( String . format ( "\r\n%02x\r\n" , i ) ) ; response . append ( "\r\n" ) ; } response . append ( "\r\n0\r\n\r\n" ) ; launchServer ( response . toString ( ) ) ; Response fetched = fetchPage ( "/" , 200 ) ; assertEquals ( "Chunked content not truncated according to http.content.limit" , 65536 , fetched . getContent ( ) . length ) ; } }